42	serve(async (req) => {
43	  if (req.method === 'OPTIONS') {
44	    return new Response('ok', { headers: corsHeaders });
45	  }
46	
47	  try {
48	    const body = await req.text();
49	    //makes sure the request is from paystack by verifying the signature using the secret key(makes sure its from paystack and not a hacker trying to fake payment)
50	    const signature = req.headers.get('x-paystack-signature');
51	    const secret = Deno.env.get('PAYSTACK_SECRET_KEY')!;
52	
53	    // ✅ Verify webhook is actually from Paystack
54	    const key = await crypto.subtle.importKey(
55	      'raw',
56	      new TextEncoder().encode(secret),
57	      { name: 'HMAC', hash: 'SHA-512' },
58	      false,
59	      ['sign']
60	    );
61	    const signatureBuffer = await crypto.subtle.sign(
62	      'HMAC',
63	      key,
64	      new TextEncoder().encode(body)
65	    );
66	    const expectedSignature = Array.from(new Uint8Array(signatureBuffer))
67	      .map(b => b.toString(16).padStart(2, '0'))
68	      .join('');
69	
70	    if (expectedSignature !== signature) {
71	      return new Response(JSON.stringify({ error: 'Invalid signature' }), {
72	        status: 401,
73	        headers: corsHeaders,
74	      });
75	    }
76	
77	    const event = JSON.parse(body);
78	    const supabase = createClient(
79	      Deno.env.get('SUPABASE_URL')!,
80	      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
81	    );
82	
83	    // ✅ Handle successful charge(when a user successfully pays for subscription)
84	    if (event.event === 'charge.success') {
85	      const { customer, metadata, plan } = event.data;
86	      const userEmail = customer.email;
87	      const subscriptionPlan = metadata?.plan || 'creative_pro';
88	
89	      // Get user by email
90	      const { data: profile } = await supabase
91	        .from('profiles')
92	        .select('id, user_type')
93	        .eq('email', userEmail)
94	        .single();
95	
96	      if (profile) {
97	        const expiresAt = new Date();
98	        expiresAt.setMonth(expiresAt.getMonth() + 1);
99	
100	        const kiraLimit = subscriptionPlan === 'business' ? 200 : 40;
101	
102	        await supabase
103	          .from('profiles')
104	          .update({
105	            subscription_plan: subscriptionPlan,
106	            subscription_status: 'active',
107	            subscription_expires_at: expiresAt.toISOString(),
108	            paystack_customer_code: customer.customer_code,
109	            kira_actions_limit: kiraLimit,
110	          })
111	          .eq('id', profile.id);
112	      }
113	    }
114	
115	    // ✅ Recurring renewal — extend expiry by one month and keep active
116	    if (event.event === 'subscription.create') {
117	      const { customer } = event.data;
118	      const expiresAt = new Date();
119	      expiresAt.setMonth(expiresAt.getMonth() + 1);
120	      await supabase
121	        .from('profiles')
122	        .update({
123	          subscription_status: 'active',
124	          subscription_expires_at: expiresAt.toISOString(),
125	        })
126	        .eq('email', customer.email);
127	    }
128	
129	    // ✅ Payment failed — cut off premium access and reset Kira limit to free tier
130	    if (event.event === 'invoice.payment_failed') {
131	      const { customer } = event.data;
132	      await supabase
133	        .from('profiles')
134	        .update({ subscription_status: 'expired', kira_actions_limit: 10 })
135	        .eq('email', customer.email);
136	    }
137	
138	    // ✅ Subscription cancelled by user — same downgrade treatment
139	    if (event.event === 'subscription.disable') {
140	      const { customer } = event.data;
141	      await supabase
142	        .from('profiles')
143	        .update({ subscription_status: 'cancelled', kira_actions_limit: 10 })
144	        .eq('email', customer.email);
145	    }
146	    //we always tell paystack that the webhook has been received if not paystack will keep retrying the webhook
147	    return new Response(JSON.stringify({ received: true }), {
148	      status: 200,
149	      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
150	    });
151	
152	  } catch (error) {
153	    console.error('Webhook error:', error.message);
154	    return new Response(JSON.stringify({ error: error.message }), {
155	      status: 500,
156	      headers: corsHeaders,
157	    });
158	  }
159	});
