85	      startOfMonth.setHours(0, 0, 0, 0);
86	
87	      const { count } = await supabase
88	        .from('invoices')
89	        .select('id', { count: 'exact', head: true })
90	        .eq('user_id', userId)
91	        .gte('created_at', startOfMonth.toISOString());
92	
93	      if ((count ?? 0) >= 5) {
94	        return new Response(JSON.stringify({
