97	        }), {
98	          status: 403,
99	          headers: { ...cors, 'Content-Type': 'application/json' },
100	        });
101	      }
102	    }
103	    // === END PLAN LIMIT GATE ===
104	
105	    // === INPUT VALIDATION ===
106	    let body: Record<string, unknown>;
107	    try {
108	      body = await req.json();
109	    } catch {
110	      return new Response(JSON.stringify({ error: 'Invalid JSON body' }), {
111	        status: 400,
112	        headers: { ...cors, 'Content-Type': 'application/json' },
113	      });
114	    }
115	
116	    const { invoice_number, client_name, client_email, client_address, issue_date,
117	            due_date, tax_rate, discount_amount, notes, terms, currency, items } = body as Record<string, unknown>;
118	
119	    if (!client_name || typeof client_name !== 'string' || client_name.trim().length === 0) {
120	      return new Response(JSON.stringify({ error: 'client_name is required' }), {
