128	        status: 400,
129	        headers: { ...cors, 'Content-Type': 'application/json' },
130	      });
131	    }
132	
133	    if (!Array.isArray(items) || items.length === 0) {
134	      return new Response(JSON.stringify({ error: 'At least one invoice item is required' }), {
135	        status: 400,
136	        headers: { ...cors, 'Content-Type': 'application/json' },
