138	    }
139	
140	    // Validate each item
141	    for (const item of items as InvoiceItem[]) {
142	      if (!item.description || typeof item.description !== 'string') {
143	        return new Response(JSON.stringify({ error: 'Each item must have a description' }), {
144	          status: 400,
