169	
170	    const resolvedTaxRate = typeof tax_rate === 'number' && tax_rate >= 0 ? tax_rate : 0;
171	    const resolvedDiscount = typeof discount_amount === 'number' && discount_amount >= 0 ? discount_amount : 0;
172	
173	    // Calculate totals
174	    const subtotal = (items as InvoiceItem[]).reduce((sum, item) => sum + (item.quantity * item.unit_price), 0);
175	    const taxAmount = subtotal * (resolvedTaxRate / 100);
176	    const total = subtotal + taxAmount - resolvedDiscount;
177	    // === END INPUT VALIDATION ===
178	
179	    // Insert invoice
180	    const { data: invoice, error: invoiceError } = await supabase
181	      .from('invoices')
182	      .insert({
183	        user_id: userId,
184	        invoice_number: resolvedInvoiceNumber,
185	        client_name: (client_name as string).trim(),
186	        client_email: typeof client_email === 'string' ? client_email.trim() : null,
187	        client_address: typeof client_address === 'string' ? client_address.trim() : null,
188	        issue_date: typeof issue_date === 'string' ? issue_date : new Date().toISOString().split('T')[0],
189	        due_date: due_date as string,
190	        status: 'draft',
191	        subtotal,
192	        tax_rate: resolvedTaxRate,
193	        tax_amount: taxAmount,
194	        discount_amount: resolvedDiscount,
195	        total,
196	        notes: typeof notes === 'string' ? notes : null,
197	        terms: typeof terms === 'string' ? terms : null,
198	        currency: resolvedCurrency,
199	      })
200	      .select()
201	      .single();
202	
203	    if (invoiceError) {
204	      console.error('invoices-create insert error:', invoiceError);
205	      return new Response(JSON.stringify({ error: 'Failed to create invoice' }), {
206	        status: 500,
207	        headers: { ...cors, 'Content-Type': 'application/json' },
208	      });
209	    }
210	
211	    // Insert invoice items
212	    const invoiceItems = (items as InvoiceItem[]).map((item) => ({
213	      invoice_id: invoice.id,
214	      description: item.description,
215	      quantity: item.quantity,
216	      unit_price: item.unit_price,
217	      total: item.quantity * item.unit_price,
218	    }));
219	
220	    const { error: itemsError } = await supabase.from('invoice_items').insert(invoiceItems);
221	
222	    if (itemsError) {
223	      console.error('invoices-create items insert error:', itemsError);
224	      // Roll back the invoice
225	      await supabase.from('invoices').delete().eq('id', invoice.id);
226	      return new Response(JSON.stringify({ error: 'Failed to save invoice items' }), {
227	        status: 500,
228	        headers: { ...cors, 'Content-Type': 'application/json' },
229	      });
230	    }
231	
232	    return new Response(JSON.stringify({ invoice: { ...invoice, items: invoiceItems } }), {
233	      status: 201,
234	      headers: { ...cors, 'Content-Type': 'application/json' },
235	    });
236	
237	  } catch (error) {
238	    console.error('invoices-create error:', error);
239	    return new Response(JSON.stringify({ error: 'Something went wrong. Please try again.' }), {
240	      status: 500,
241	      headers: { ...cors, 'Content-Type': 'application/json' },
242	    });
243	  }
244	});
